import React, { useEffect, useState } from 'react';
import { useNavigate, NavLink } from 'react-router-dom';
import { 
  LayoutDashboard, Shirt, Maximize, Palette, 
  Sparkles, Heart, History, User, LogOut 
} from 'lucide-react';
import './styles/Sidebar.css';

const Sidebar = () => {
  const navigate = useNavigate();
  const [userData, setUserData] = useState({ 
    name: "Guest", 
    profileImage: "" 
  });

  // This is your backend address
  const API_URL = "http://localhost:5000";

  useEffect(() => {
    const storedUser = localStorage.getItem('user');
    if (storedUser) {
      setUserData(JSON.parse(storedUser));
    }
  }, []);

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    navigate('/auth');
  }

  // HELPER: This creates the full path for the image
  const getProfileImage = () => {
    if (userData.profileImage && userData.profileImage.startsWith('/uploads')) {
      return `${API_URL}${userData.profileImage}`;
    }
    // Fallback to a default if no image exists
    return userData.profileImage || "https://i.pravatar.cc/150?u=fallback";
  };

  return (
    <aside className="sidebar-master">
      <div className="sidebar-header">
        <div className="user-profile">
          <div className="avatar-wrapper">
            <img 
              src={getProfileImage()} 
              alt="User Profile" 
              onError={(e) => { e.target.src = "https://i.pravatar.cc/150?u=error"; }}
            />
            <div className="status-indicator"></div>
          </div>
          <div className="user-meta">
            <span className="user-name">{userData.name}</span>
            <span className="user-status">Pro Member</span>
          </div>
        </div>
      </div>

      <nav className="sidebar-nav">
        <NavLink to="/dashboard" className={({ isActive }) => isActive ? "nav-link active" : "nav-link"}>
          <div className="link-icon"><LayoutDashboard size={20} /></div>
          <span className="link-text">Dashboard Home</span>
        </NavLink>
        <NavLink to="/try-on" className={({ isActive }) => isActive ? "nav-link active" : "nav-link"}>
          <div className="link-icon"><Shirt size={20} /></div>
          <span className="link-text">Virtual Try-On</span>
        </NavLink>
        {/* ... Keep your other NavLinks here ... */}
      </nav>

      <div className="sidebar-footer">
        <button className="logout-btn" onClick={handleLogout}>
          <div className="logout-icon-box"><LogOut size={18} /></div>
          <span>Logout</span>
        </button>
      </div>
    </aside>
  );
};

export default Sidebar;
